// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./interfaces/ISomniaAgents.sol";

contract DrugInfo {
    IAgentRequester public constant PLATFORM =
        IAgentRequester(0x037Bb9C718F3f7fe5eCBDB0b600D607b52706776);

    uint256 public constant WEB_AGENT_ID = 12875401142070969085;

    string[] public drugNames;
    string[] public searchResults;
    mapping(uint256 => uint256) public requestToResultIndex;

    event DrugInfoRequested(uint256 indexed requestId, string drugName);
    event DrugInfoReceived(uint256 indexed requestId, string drugName, string result);
    event DrugInfoFailed(uint256 indexed requestId, ResponseStatus status);

    function getDrugInfo(string calldata drugName) external payable returns (uint256 requestId) {
        string memory url = string.concat("https://www.drugs.com/", drugName, ".html");
        string memory prompt = string.concat(
            "Extract the uses, dosage, and side effects of ", drugName,
            " from this page."
        );

        string[] memory options = new string[](0);

        bytes memory payload = abi.encodeWithSelector(
            IParseWebsiteAgent.ExtractString.selector,
            "summary",
            "Uses, dosage, and side effects",
            options,
            prompt,
            url,
            false,    // direct scrape, don't search
            1
        );

        uint256 deposit = PLATFORM.getRequestDeposit();
        uint256 required = deposit + 0.10 ether * 3;
        require(msg.value >= required, "Need 0.33 STT total");

        requestId = PLATFORM.createRequest{value: msg.value}(
            WEB_AGENT_ID,
            address(this),
            this.handleResult.selector,
            payload
        );

        drugNames.push(drugName);
        searchResults.push("");
        requestToResultIndex[requestId] = searchResults.length - 1;

        emit DrugInfoRequested(requestId, drugName);
    }

    function handleResult(
        uint256 requestId,
        Response[] memory responses,
        ResponseStatus status,
        Request memory
    ) external {
        require(msg.sender == address(PLATFORM), "Only platform");

        uint256 idx = requestToResultIndex[requestId];

        if (status == ResponseStatus.Success && responses.length > 0) {
            string memory result = abi.decode(responses[0].result, (string));
            searchResults[idx] = result;
            emit DrugInfoReceived(requestId, drugNames[idx], result);
        } else {
            searchResults[idx] = "Unable to retrieve drug information.";
            emit DrugInfoFailed(requestId, status);
        }
    }

    function getResultCount() external view returns (uint256) {
        return searchResults.length;
    }

    function getResult(uint256 index) external view returns (string memory drugName, string memory result) {
        return (drugNames[index], searchResults[index]);
    }

    function getRequiredDeposit() external view returns (uint256) {
        return PLATFORM.getRequestDeposit();
    }

    receive() external payable {}
}

contracts/interfaces/ISomniaAgents.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

enum ConsensusType {
    Majority,
    Threshold
}

enum ResponseStatus {
    None,
    Pending,
    Success,
    Failed,
    TimedOut
}

struct Response {
    address validator;
    bytes result;
    ResponseStatus status;
    uint256 receipt;
    uint256 timestamp;
    uint256 executionCost;
}

struct Request {
    uint256 id;
    address requester;
    address callbackAddress;
    bytes4 callbackSelector;
    address[] subcommittee;
    Response[] responses;
    uint256 responseCount;
    uint256 failureCount;
    uint256 threshold;
    uint256 createdAt;
    uint256 deadline;
    ResponseStatus status;
    ConsensusType consensusType;
    uint256 remainingBudget;
}

interface IAgentRequester {
    event RequestCreated(
        uint256 indexed requestId,
        uint256 indexed agentId,
        uint256 perAgentBudget,
        bytes payload,
        address[] subcommittee
    );
    event RequestFinalized(uint256 indexed requestId, ResponseStatus status);

    function createRequest(
        uint256 agentId,
        address callbackAddress,
        bytes4 callbackSelector,
        bytes calldata payload
    ) external payable returns (uint256 requestId);

    function createAdvancedRequest(
        uint256 agentId,
        address callbackAddress,
        bytes4 callbackSelector,
        bytes calldata payload,
        uint256 subcommitteeSize,
        uint256 threshold,
        ConsensusType consensusType,
        uint256 timeout
    ) external payable returns (uint256 requestId);

    function getRequest(uint256 requestId) external view returns (Request memory);
    function hasRequest(uint256 requestId) external view returns (bool);
    function getRequestDeposit() external view returns (uint256);
    function getAdvancedRequestDeposit(uint256 subcommitteeSize) external view returns (uint256);
}

interface IJsonApiAgent {
    function fetchString(string calldata url, string calldata selector) external returns (string memory);
    function fetchUint(string calldata url, string calldata selector, uint8 decimals) external returns (uint256);
    function fetchInt(string calldata url, string calldata selector, uint8 decimals) external returns (int256);
    function fetchBool(string calldata url, string calldata selector) external returns (bool);
    function fetchStringArray(string calldata url, string calldata selector) external returns (string[] memory);
    function fetchUintArray(string calldata url, string calldata selector, uint8 decimals) external returns (uint256[] memory);
}

interface ILLMAgent {
    function inferString(
        string calldata prompt,
        string calldata system,
        bool chainOfThought,
        string[] calldata allowedValues
    ) external returns (string memory);

    function inferNumber(
        string calldata prompt,
        string calldata system,
        int256 minValue,
        int256 maxValue,
        bool chainOfThought
    ) external returns (int256);

    function inferChat(
        string[] calldata roles,
        string[] calldata messages,
        bool chainOfThought
    ) external returns (string memory);
}

interface IParseWebsiteAgent {
    function ExtractString(
        string calldata key,
        string calldata description,
        string[] calldata options,
        string calldata prompt,
        string calldata url,
        bool resolveUrl,
        uint8 numPages
    ) external returns (string memory);

    function ExtractANumber(
        string calldata key,
        string calldata description,
        uint256 min,
        uint256 max,
        string calldata prompt,
        string calldata url,
        bool resolveUrl,
        uint8 numPages
    ) external returns (uint256);
}
